// WF-Val Aggregation: WF3-Liveness (execution) + DB-Konsistenz + Nayax-Schreibstillstand-Gegencheck
const WF3_MAX_SUCCESS_AGE_MIN = 30;
const WRITE_STALL_THRESHOLD_MIN = 30;  // Nayax > DB um mehr als das = WF3 laeuft, schreibt aber nicht
function clean(v){ return String(v==null?'':v).replace(/\s+/g,' ').trim(); }
const CHECK_LABELS = {
  keine_preise:'Aktive Slots ohne Preis', negative_qty:'Negative Lagermengen',
  alte_warnungen:'Alte ungeloeste Warnungen (>7 Tage)', pending_proposals:'Offene Rechnungsvorschlaege (>14 Tage)' };

// DB-Konsistenz-Rows (ohne den _db_latest_sale-Hilfsrow)
const allDb = $('DB - Konsistenzcheck').all().filter(i => i.json && i.json.check_type);
const dbLatestRow = allDb.find(r => r.json.check_type === '_db_latest_sale');
const dbLatestIso = dbLatestRow ? clean(dbLatestRow.json.message) : '';
const otherItems = allDb.filter(r => r.json.check_type !== '_db_latest_sale');
const hasOtherIssues = otherItems.length > 0;

// WF3-Liveness (execution-basiert)
let wf3Unhealthy=false, wf3Reason='', wf3Determined=false;
try {
  const row = $('PG n8n - WF3 Execution-Check').first().json;
  const ageRaw = (row && row.wf3_last_success_age_min != null) ? Number(row.wf3_last_success_age_min) : null;
  const lastStatus = (row && row.wf3_last_status) ? row.wf3_last_status : '?';
  if (ageRaw != null && Number.isFinite(ageRaw)) {
    wf3Determined = true;
    if (ageRaw > WF3_MAX_SUCCESS_AGE_MIN) {
      wf3Unhealthy = true;
      wf3Reason = 'Letzter erfolgreicher WF3-Lauf vor ' + Math.round(ageRaw) + ' Min (Limit ' + WF3_MAX_SUCCESS_AGE_MIN + ' Min). Letzter Lauf-Status: ' + lastStatus + '.';
    }
  }
} catch (e) {}

// Nayax-Schreibstillstand: nur wenn WF3 GESUND laeuft, aber Nayax der DB voraus ist
let writeStall=false, writeStallReason='';
try {
  const nx = $('Nayax - lastSales Collapse').first().json;
  const nayaxOk = !!(nx && nx.nayax_ok);
  const nayaxMs = (nx && nx.nayax_latest_ms != null) ? Number(nx.nayax_latest_ms) : null;
  const dbMs = dbLatestIso ? Date.parse(dbLatestIso) : null;
  if (wf3Determined && !wf3Unhealthy && nayaxOk && Number.isFinite(nayaxMs) && Number.isFinite(dbMs)) {
    const gapMin = (nayaxMs - dbMs) / 60000;
    if (gapMin > WRITE_STALL_THRESHOLD_MIN) {
      writeStall = true;
      writeStallReason = 'Nayax hat Verkaeufe bis ' + nx.nayax_latest_iso + ', DB nur bis ' + dbLatestIso + ' (Rueckstand ' + Math.round(gapMin) + ' Min). WF3 laeuft, persistiert aber nicht.';
    }
  }
} catch (e) {}

const hasIssues = wf3Unhealthy || writeStall || hasOtherIssues;
if (!hasIssues) {
  return [{ json: { status:'OK', count:0, has_issues:false, restart_flag:'NEIN', wf3_determined:wf3Determined,
    email_subject:null, email_body:null,
    summary:'Alle Pruefungen bestanden (DB-Konsistenz ok; WF3 ' + (wf3Determined?'laeuft':'Status unbestimmt') + '; Nayax<->DB synchron).' } }];
}

const grouped = {};
for (const { json: r } of otherItems) { if(!grouped[r.check_type]) grouped[r.check_type]=[]; grouped[r.check_type].push(r.message); }
const otherLines = Object.entries(grouped).map(([type,msgs]) => {
  const label = CHECK_LABELS[type] || type;
  return '<h3 style="color:#c0392b">' + label + ' (' + msgs.length + ')</h3><ul>' + msgs.map(m=>'<li>'+m+'</li>').join('') + '</ul>'; }).join('');
const wf3Section = wf3Unhealthy ? '<h3 style="color:#e67e22">WF3 Verkaufsworkflow haengt - Auto-Neustart ausgeloest</h3><ul><li>'+wf3Reason+'</li></ul>' : '';
const stallSection = writeStall ? '<h3 style="color:#c0392b">WF3 schreibt nicht (Nayax-Gegencheck)</h3><ul><li>'+writeStallReason+'</li></ul>' : '';
const ts = new Date().toISOString();
const totalCount = otherItems.length + (wf3Unhealthy?1:0) + (writeStall?1:0);
return [{ json: {
  status:'FEHLER', count:totalCount, has_issues:true,
  restart_flag: wf3Unhealthy ? 'JA' : 'NEIN',
  wf3_determined: wf3Determined, write_stall: writeStall,
  email_subject: '[DB-Check] ' + totalCount + ' Problem' + (totalCount!==1?'e':'') + ' - Automatenlager',
  email_body: '<h2 style="color:#c0392b">WF-Val Pruefung: ' + totalCount + ' Problem' + (totalCount!==1?'e':'') + '</h2>' + wf3Section + stallSection + otherLines + '<hr><p style="color:#888;font-size:12px">WF-Val Check: ' + ts + '</p>' } }];

// Nayax lastSales -> ein Item mit max Settlement-Zeit (mirror WF3 'Normalize Sales')
function clean(v){ return String(v==null?'':v).replace(/\s+/g,' ').trim(); }
function parseGmt(s){ let t=clean(s).replace(' ','T'); if(!t) return NaN;
  if(!/[zZ]$/.test(t) && !/[+\-]\d{2}:?\d{2}$/.test(t)) t+='Z';
  return Date.parse(t); }
const items=$input.all();
let sales=[];
for(const it of items){ const d=it.json;
  if(Array.isArray(d)) sales.push(...d);
  else if(d && Array.isArray(d.body)) sales.push(...d.body);
  else if(d && typeof d==='object') sales.push(d); }
let maxMs=null, maxIso='';
for(const s of sales){
  const ms=parseGmt(s.SettlementDateTimeGMT || s.MachineAuthorizationTime || s.AuthorizationDateTimeGMT);
  if(Number.isFinite(ms) && (maxMs===null || ms>maxMs)){ maxMs=ms; maxIso=new Date(ms).toISOString(); } }
const ok = sales.length>0 && maxMs!==null;
return [{ json: { nayax_ok: ok, nayax_count: sales.length, nayax_latest_ms: maxMs, nayax_latest_iso: maxIso } }];

